import { Avatar, Card, CardContent, CardHeader, Divider, IconButton, Typography} from '@material-ui/core'
import { MoreVert} from '@material-ui/icons'
import { makeStyles } from '@material-ui/styles'
import React from 'react'

const useStyle =makeStyles({
  avatar: {
    background: '#162276'
  }
})

export default function SubjectCards({ subject }) {
  const classes = useStyle()
  return (
    <div>
        <Card elevation={1}>
            <CardHeader
            avatar={
              <Avatar className={classes.avatar}>
                P
              </Avatar>
            }
              action={
                <IconButton>
                  <MoreVert/>
                </IconButton>
              }
              title = {subject.title}
              subheader = {subject.instructor}
              subheader = {subject.time}
            />
            <Divider />
            <CardContent>
              <Typography>
                {subject.body}
              </Typography>
            </CardContent>
        </Card>
    </div>
  )
}
